<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***WebSocketServerforReal-timeUpdates*RatchetWebSocketImplementation*/require_once__DIR__.'/../vendor/autoload.php';useRatchet\MessageComponentInterface;useRatchet\ConnectionInterface;useRatchet\Server\IoServer;useRatchet\Http\HttpServer;useRatchet\WebSocket\WsServer;classSPRINWebSocketimplementsMessageComponentInterface{protected$clients;protected$userConnections;protected$db;publicfunction__construct(){$this->clients=new\SplObjectStorage;$this->userConnections=[];/Initializedatabaseconnectiontry{$dsn="mysql:host=localhost;dbname=bagops;unix_socket=/opt/lampp/var/mysql/mysql.sock";$this->db=newPDO($dsn,'root','root');$this->db->setAttribute(PDO::ATTR_ERRMODE,PDO::ERRMODE_EXCEPTION);}catch(PDOException$e){error_log("WebSocketDBconnectionfailed:".$e->getMessage());}}/***Newconnectionestablished*/publicfunctiononOpen(ConnectionInterface$conn){$this->clients->attach($conn);echo"Newconnection!({$conn->resourceId})\n";/Sendwelcomemessage$conn->send(json_encode(['type'=>'welcome','message'=>'ConnectedtoSPRINReal-timeServer','timestamp'=>date('c'),'connection_id'=>$conn->resourceId]));}/***Messagereceivedfromclient*/publicfunctiononMessage(ConnectionInterface$from,$msg){$data=json_decode($msg,true);if(!$data||!isset($data['action'])){$from->send(json_encode(['type'=>'error','message'=>'Invalidmessageformat']));return;}switch($data['action']){case'auth':$this->handleAuth($from,$data);break;case'subscribe':$this->handleSubscribe($from,$data);break;case'unsubscribe':$this->handleUnsubscribe($from,$data);break;case'ping':$from->send(json_encode(['type'=>'pong','timestamp'=>date('c')]));break;case'get_stats':$this->handleGetStats($from);break;default:$from->send(json_encode(['type'=>'error','message'=>'Unknownaction:'.$data['action']]));}}/***Handleauthentication*/protectedfunctionhandleAuth(ConnectionInterface$conn,$data){$token=$data['token']??null;if(!$token){$conn->send(json_encode(['type'=>'error','message'=>'Authenticationtokenrequired']));return;}/VerifyJWTtoken(ifJWTAuthisavailable)$conn->userData=['authenticated'=>true,'token'=>$token,'subscribed_channels'=>[]];$this->userConnections[$conn->resourceId]=$conn;$conn->send(json_encode(['type'=>'auth_success','message'=>'Authenticationsuccessful','connection_id'=>$conn->resourceId]));}/***Handlechannelsubscription*/protectedfunctionhandleSubscribe(ConnectionInterface$conn,$data){$channel=$data['channel']??null;if(!$channel){$conn->send(json_encode(['type'=>'error','message'=>'Channelnamerequired']));return;}$validChannels=['personil_updates','schedule_updates','notifications'];if(!in_array($channel,$validChannels)){$conn->send(json_encode(['type'=>'error','message'=>'Invalidchannel:'.$channel]));return;}if(!isset($conn->subscribedChannels)){$conn->subscribedChannels=[];}$conn->subscribedChannels[]=$channel;$conn->send(json_encode(['type'=>'subscribed','channel'=>$channel,'message'=>'Subscribedto'.$channel]));}/***Handleunsubscribe*/protectedfunctionhandleUnsubscribe(ConnectionInterface$conn,$data){$channel=$data['channel']??null;if($channel&&isset($conn->subscribedChannels)){$conn->subscribedChannels=array_diff($conn->subscribedChannels,[$channel]);}$conn->send(json_encode(['type'=>'unsubscribed','channel'=>$channel,'message'=>'Unsubscribedfrom'.$channel]));}/***Getreal-timestatistics*/protectedfunctionhandleGetStats(ConnectionInterface$conn){try{$stats=[];/Getpersonilcount$stmt=$this->db->query("SELECTCOUNT(*)ascountFROMpersonilWHEREis_deleted=false");$stats['total_personil']=$stmt->fetch()['count'];/Getactiveschedules$today=date('Y-m-d');$stmt=$this->db->query("SELECTCOUNT(*)ascountFROMschedulesWHEREtanggal='$today'ANDis_deleted=false");$stats['schedules_today']=$stmt->fetch()['count'];$conn->send(json_encode(['type'=>'stats','data'=>$stats,'timestamp'=>date('c')]));}catch(PDOException$e){$conn->send(json_encode(['type'=>'error','message'=>'Databaseerror:'.$e->getMessage()]));}}/***Broadcastmessagetoallsubscribedclients*/publicfunctionbroadcast($channel,$data){$message=json_encode(['type'=>'broadcast','channel'=>$channel,'data'=>$data,'timestamp'=>date('c')]);forforeach($this->clientsas$client){if(isset($client->subscribedChannels)&&in_array($channel,$client->subscribedChannels)){$client->send($message);}}}/***Connectionclosed*/publicfunctiononClose(ConnectionInterface$conn){$this->clients->detach($conn);unset($this->userConnections[$conn->resourceId]);echo"Connection{$conn->resourceId}hasdisconnected\n";}/***Erroroccurred*/publicfunctiononError(ConnectionInterface$conn,\Exception$e){echo"Anerrorhasoccurred:{$e->getMessage()}\n";$conn->close();}/***StartWebSocketserver*/publicstaticfunctionrun($port=8080){$server=IoServer::factory(newHttpServer(newWsServer(newself())),$port);echo"WebSocketserverrunningonport{$port}\n";$server->run();}}/CLIusageif(php_sapi_name()==='cli'&&isset($argv[1])&&$argv[1]==='start'){$port=$argv[2]??8080;SPRINWebSocket::run($port);}?>
